COPY public.club_local_rules (id, club_id, rules, course_ratings, footer_notes, updated_at) FROM stdin;
1	1	[{"id": "r1", "body": "Penalty areas are demarcated by RED or YELLOW stakes. Relief from these penalty areas must be taken in accordance with the Rules of Golf.\\nOptional drop zones are provided on Holes 3 and 17", "title": "1. Penalty Areas"}, {"id": "r2", "body": "Beyond all boundary fences and white stakes on holes 1, 16 and 18.\\nNo relief is granted from the Out of Bounds perimeter fence.", "title": "2. Out of Bounds"}, {"id": "r3", "body": "All flower beds, staked trees, artificially surfaced roads and paths are deemed to be GUR. This includes areas that are ringed in white paint or marked as GUR. The ball may be dropped without penalty within 1 club length of the nearest point of relief, no nearer the hole.", "title": "3. Ground Under Repair"}, {"id": "r4", "body": "All distance and hazard markers. Stones in the bunkers may be removed.", "title": "4. Movable Obstructions"}, {"id": "r5", "body": "- Halfway house and all lightning shelters.\\n- All Fairway distance poles are to be treated as immovable obstructions. Relief may be taken for stance or swing path interference.\\nNo line of play relief is granted.", "title": "5. Immovable Obstructions"}, {"id": "r6", "body": "One blast signals play to be suspended immediately. Failure to stop play will result in disqualification. Play may only resume once the siren has been sounded twice. If the siren sounds three times the course has been closed for play and players must return to the club house.", "title": "6. Lightning Siren"}]	[{"id": "cr1", "tee": "Yellow (Mens)", "color": "#d4a800", "slope_rating": "138", "course_rating": "74.7"}, {"id": "cr2", "tee": "Yellow (Ladies)", "color": "#d4a800", "slope_rating": "155", "course_rating": "81.2"}, {"id": "cr3", "tee": "White (Mens)", "color": "#6b7280", "slope_rating": "136", "course_rating": "73.4"}, {"id": "cr4", "tee": "White (Ladies)", "color": "#6b7280", "slope_rating": "151", "course_rating": "80.1"}, {"id": "cr5", "tee": "Blue (Mens)", "color": "#3b82f6", "slope_rating": "134", "course_rating": "69.8"}, {"id": "cr6", "tee": "Blue (Ladies)", "color": "#3b82f6", "slope_rating": "145", "course_rating": "76.1"}, {"id": "cr7", "tee": "Red (Mens)", "color": "#ef4444", "slope_rating": "130", "course_rating": "67.2"}, {"id": "cr8", "tee": "Red (Ladies)", "color": "#ef4444", "slope_rating": "138", "course_rating": "73.5"}]	All distances are in meters and measured to the middle of the green\nWhite Flag - Front of green\nYellow Flag - Middle of green\nRed Flag - Back of green\nPlus Strokes: 12th / 6th / 18th / 1st	2026-06-16 08:25:10.658663
\.
